export type DuaCategory = 'Morning' | 'Evening' | 'Sleep' | 'Travel' | 'Hardship' | 'Gratitude' | 'General';

export interface Dua {
  id: string;
  title: string;
  category: DuaCategory;
  arabic: string;
  transliteration: string;
  translation: string;
  reference?: string;
}

export interface SalahStatus {
  fajr: boolean;
  dhuhr: boolean;
  asr: boolean;
  maghrib: boolean;
  isha: boolean;
  tahajjud: boolean;
}

export interface DailyRecord {
  date: string;
  salah: SalahStatus;
  dhikrCount: number;
}

export interface Reminder {
  id: string;
  label: string;
  time: string;
  enabled: boolean;
}

import React, { useState, useEffect } from 'react';
import { Routes, Route, useNavigate, useLocation } from 'react-router-dom';
import { Home, BookOpen, CheckCircle, Bell, User, Heart, Settings, ChevronRight } from 'lucide-react';
import Dashboard from './components/Dashboard';
import DuaLibrary from './components/DuaLibrary';
import Tracker from './components/Tracker';
import Reminders from './components/Reminders';
import { DailyRecord, Dua } from './types';

const App: React.FC = () => {
  const navigate = useNavigate();
  const location = useLocation();
  const [bookmarks, setBookmarks] = useState<string[]>([]);
  const [dailyRecords, setDailyRecords] = useState<DailyRecord[]>([]);
  const [currentDate] = useState(new Date().toISOString().split('T')[0]);

  useEffect(() => {
    const savedBookmarks = localStorage.getItem('dua_bookmarks');
    if (savedBookmarks) setBookmarks(JSON.parse(savedBookmarks));

    const savedRecords = localStorage.getItem('daily_records');
    if (savedRecords) setDailyRecords(JSON.parse(savedRecords));
  }, []);

  const toggleBookmark = (id: string) => {
    setBookmarks(prev => {
      const next = prev.includes(id) ? prev.filter(b => b !== id) : [...prev, id];
      localStorage.setItem('dua_bookmarks', JSON.stringify(next));
      return next;
    });
  };

  const updateRecord = (record: DailyRecord) => {
    setDailyRecords(prev => {
      const index = prev.findIndex(r => r.date === record.date);
      let next;
      if (index > -1) {
        next = [...prev];
        next[index] = record;
      } else {
        next = [...prev, record];
      }
      localStorage.setItem('daily_records', JSON.stringify(next));
      return next;
    });
  };

  const NavItem = ({ to, icon: Icon, label }: { to: string; icon: any; label: string }) => {
    const isActive = location.pathname === to;
    return (
      <button
        onClick={() => navigate(to)}
        className={`flex flex-col items-center justify-center space-y-1 w-full py-2 transition-colors ${
          isActive ? 'text-emerald-700' : 'text-stone-400 hover:text-emerald-600'
        }`}
      >
        <Icon size={24} />
        <span className="text-[10px] font-medium uppercase tracking-wider">{label}</span>
      </button>
    );
  };

  return (
    <div className="max-w-md mx-auto min-h-screen flex flex-col bg-stone-50 shadow-2xl relative border-x border-stone-100">
      {/* Header */}
      <header className="px-6 pt-8 pb-4 bg-white sticky top-0 z-30 flex justify-between items-center border-b border-stone-100">
        <div>
          <h1 className="text-xl font-bold text-emerald-900">Companion</h1>
          <p className="text-xs text-stone-500">{new Date().toLocaleDateString('en-US', { weekday: 'long', day: 'numeric', month: 'long' })}</p>
        </div>
        <div className="flex space-x-3">
          <button className="p-2 bg-stone-50 rounded-full text-stone-500 hover:text-emerald-700 transition-colors">
            <Heart size={20} fill={bookmarks.length > 0 ? "currentColor" : "none"} />
          </button>
          <button className="p-2 bg-stone-50 rounded-full text-stone-500 hover:text-emerald-700 transition-colors">
            <User size={20} />
          </button>
        </div>
      </header>

      {/* Main Content */}
      <main className="flex-1 pb-24 overflow-y-auto px-6 pt-6">
        <Routes>
          <Route path="/" element={<Dashboard records={dailyRecords} />} />
          <Route path="/duas" element={<DuaLibrary bookmarks={bookmarks} toggleBookmark={toggleBookmark} />} />
          <Route path="/tracker" element={<Tracker records={dailyRecords} updateRecord={updateRecord} />} />
          <Route path="/reminders" element={<Reminders />} />
        </Routes>
      </main>

      {/* Bottom Nav */}
      <nav className="fixed bottom-0 left-1/2 -translate-x-1/2 w-full max-w-md bg-white/90 backdrop-blur-md border-t border-stone-200 flex justify-around items-center px-4 py-1 z-40">
        <NavItem to="/" icon={Home} label="Home" />
        <NavItem to="/duas" icon={BookOpen} label="Duas" />
        <NavItem to="/tracker" icon={CheckCircle} label="Track" />
        <NavItem to="/reminders" icon={Bell} label="Alerts" />
      </nav>
    </div>
  );
};

export default App;

import React, { useState, useMemo } from 'react';
import { Search, Heart, Filter, ChevronDown, Share2 } from 'lucide-react';
import { DUAS } from '../constants';
import { DuaCategory, Dua } from '../types';

interface DuaLibraryProps {
  bookmarks: string[];
  toggleBookmark: (id: string) => void;
}

const CATEGORIES: DuaCategory[] = ['General', 'Morning', 'Evening', 'Sleep', 'Travel', 'Hardship', 'Gratitude'];

const DuaLibrary: React.FC<DuaLibraryProps> = ({ bookmarks, toggleBookmark }) => {
  const [activeCategory, setActiveCategory] = useState<DuaCategory | 'All'>('All');
  const [searchQuery, setSearchQuery] = useState('');
  const [expandedId, setExpandedId] = useState<string | null>(null);

  const filteredDuas = useMemo(() => {
    return DUAS.filter(dua => {
      const matchesCategory = activeCategory === 'All' || dua.category === activeCategory;
      const matchesSearch = dua.title.toLowerCase().includes(searchQuery.toLowerCase()) ||
                          dua.translation.toLowerCase().includes(searchQuery.toLowerCase());
      return matchesCategory && matchesSearch;
    });
  }, [activeCategory, searchQuery]);

  const DuaCard = ({ dua }: { dua: Dua }) => {
    const isBookmarked = bookmarks.includes(dua.id);
    const isExpanded = expandedId === dua.id;

    return (
      <div className={`bg-white rounded-3xl border border-stone-100 overflow-hidden transition-all duration-300 ${isExpanded ? 'ring-2 ring-emerald-500/20' : 'hover:shadow-lg hover:shadow-stone-200/50'}`}>
        <div className="p-5">
          <div className="flex justify-between items-start mb-4">
            <div>
              <span className="text-[10px] font-bold text-emerald-600 bg-emerald-50 px-2 py-0.5 rounded-full uppercase tracking-tighter mb-1 inline-block">
                {dua.category}
              </span>
              <h4 className="text-lg font-bold text-stone-800 leading-tight">{dua.title}</h4>
            </div>
            <button 
              onClick={() => toggleBookmark(dua.id)}
              className={`p-2 rounded-full transition-colors ${isBookmarked ? 'text-rose-500 bg-rose-50' : 'text-stone-300 bg-stone-50'}`}
            >
              <Heart size={18} fill={isBookmarked ? "currentColor" : "none"} />
            </button>
          </div>

          <div className="arabic-font text-2xl text-emerald-900 leading-[1.8] text-right my-4" dir="rtl">
            {dua.arabic}
          </div>

          <div className="space-y-4">
            <button 
              onClick={() => setExpandedId(isExpanded ? null : dua.id)}
              className="w-full flex items-center justify-center space-x-1 py-1 text-stone-400 hover:text-emerald-600 transition-colors"
            >
              <ChevronDown size={16} className={`transform transition-transform ${isExpanded ? 'rotate-180' : ''}`} />
              <span className="text-xs font-medium uppercase">{isExpanded ? 'Show Less' : 'Read Translation'}</span>
            </button>

            {isExpanded && (
              <div className="pt-4 border-t border-stone-50 space-y-4 animate-in fade-in slide-in-from-top-2 duration-300">
                <div>
                    <h5 className="text-[10px] uppercase tracking-wider text-stone-400 font-bold mb-1">Transliteration</h5>
                    <p className="text-sm text-stone-600 italic leading-relaxed">{dua.transliteration}</p>
                </div>
                <div>
                    <h5 className="text-[10px] uppercase tracking-wider text-stone-400 font-bold mb-1">Translation</h5>
                    <p className="text-sm text-stone-800 font-medium leading-relaxed">{dua.translation}</p>
                </div>
                <div className="flex justify-between items-center pt-2">
                    <span className="text-[10px] text-stone-400 italic">Ref: {dua.reference}</span>
                    <button className="flex items-center space-x-2 text-emerald-600 text-xs font-bold hover:bg-emerald-50 px-3 py-1.5 rounded-lg transition-colors">
                        <Share2 size={14} />
                        <span>Share</span>
                    </button>
                </div>
              </div>
            )}
          </div>
        </div>
      </div>
    );
  };

  return (
    <div className="space-y-6 animate-in fade-in duration-500">
      {/* Search & Categories */}
      <div className="space-y-4">
        <div className="relative">
          <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-stone-400" size={18} />
          <input 
            type="text" 
            placeholder="Search Duas, translations..." 
            value={searchQuery}
            onChange={(e) => setSearchQuery(e.target.value)}
            className="w-full pl-12 pr-4 py-4 bg-white border border-stone-100 rounded-2xl text-sm focus:outline-none focus:ring-2 focus:ring-emerald-500/10 focus:border-emerald-300 transition-all shadow-sm"
          />
