import React, { useState, useEffect } from 'react';
import { Plus, Minus, RotateCcw, Calendar, CheckCircle2 } from 'lucide-react';
import { DailyRecord, SalahStatus } from '../types';
import { SALAH_NAMES } from '../constants';

interface TrackerProps {
  records: DailyRecord[];
  updateRecord: (record: DailyRecord) => void;
}

const Tracker: React.FC<TrackerProps> = ({ records, updateRecord }) => {
  const today = new Date().toISOString().split('T')[0];
  const [currentRecord, setCurrentRecord] = useState<DailyRecord>({
    date: today,
    salah: { fajr: false, dhuhr: false, asr: false, maghrib: false, isha: false, tahajjud: false },
    dhikrCount: 0
  });

  useEffect(() => {
    const existing = records.find(r => r.date === today);
    if (existing) {
      setCurrentRecord(existing);
    }
  }, [records, today]);

  const toggleSalah = (name: keyof SalahStatus) => {
    const nextSalah = { ...currentRecord.salah, [name]: !currentRecord.salah[name] };
    const nextRecord = { ...currentRecord, salah: nextSalah };
    setCurrentRecord(nextRecord);
    updateRecord(nextRecord);
  };

  const updateDhikr = (val: number) => {
    const nextCount = Math.max(0, currentRecord.dhikrCount + val);
    const nextRecord = { ...currentRecord, dhikrCount: nextCount };
    setCurrentRecord(nextRecord);
    updateRecord(nextRecord);
  };

  const resetDhikr = () => {
    const nextRecord = { ...currentRecord, dhikrCount: 0 };
    setCurrentRecord(nextRecord);
    updateRecord(nextRecord);
  };

  return (
    <div className="space-y-8 animate-in fade-in duration-500 pb-10">
      {/* Header Info */}
      <div className="bg-white p-6 rounded-3xl border border-stone-100 shadow-sm flex items-center justify-between">
        <div className="flex items-center space-x-3">
          <div className="w-12 h-12 bg-emerald-50 rounded-2xl flex items-center justify-center text-emerald-600">
            <Calendar size={24} />
          </div>
          <div>
            <p className="text-xs text-stone-400 font-bold uppercase tracking-wider">Today's Progress</p>
            <p className="text-lg font-bold text-stone-800">Spiritual Log</p>
          </div>
        </div>
        <div className="text-right">
          <p className="text-2xl font-black text-emerald-600">
            {Math.round(((Object.values(currentRecord.salah).filter(Boolean).length / 5) * 100))}%
          </p>
          <p className="text-[10px] text-stone-400 uppercase tracking-tighter">Salah Score</p>
        </div>
      </div>

      {/* Salah Checklist */}
      <section>
        <h3 className="font-bold text-stone-800 mb-4 px-1">Daily Salah</h3>
        <div className="grid gap-3">
          {SALAH_NAMES.map((name) => (
            <button
              key={name}
              onClick={() => toggleSalah(name)}
              className={`flex items-center justify-between p-4 rounded-2xl border transition-all ${
                currentRecord.salah[name]
                  ? 'bg-emerald-50 border-emerald-200 text-emerald-800'
                  : 'bg-white border-stone-100 text-stone-400'
              }`}
            >
              <div className="flex items-center space-x-3">
                <div className={`w-6 h-6 rounded-full border-2 flex items-center justify-center ${
                  currentRecord.salah[name] ? 'bg-emerald-500 border-emerald-500' : 'border-stone-200'
                }`}>
                  {currentRecord.salah[name] && <CheckCircle2 size={16} className="text-white" />}
                </div>
                <span className={`font-bold capitalize ${currentRecord.salah[name] ? 'text-emerald-900' : 'text-stone-700'}`}>
                  {name}
                </span>
              </div>
              <span className="text-[10px] uppercase font-bold tracking-widest opacity-60">
                {currentRecord.salah[name] ? 'Completed' : 'Pending'}
              </span>
            </button>
          ))}
        </div>
      </section>

      {/* Dhikr Counter */}
      <section className="bg-gradient-to-tr from-stone-900 to-stone-800 p-8 rounded-[2rem] text-white relative overflow-hidden">
        <div className="absolute top-0 right-0 p-8 opacity-5">
             <RotateCcw size={140} />
        </div>
        <div className="relative z-10 text-center space-y-6">
          <div className="space-y-1">
            <h3 className="text-stone-400 text-[10px] uppercase font-bold tracking-widest">Global Dhikr Count</h3>
            <p className="text-6xl font-black tabular-nums tracking-tighter">{currentRecord.dhikrCount}</p>
          </div>

          <div className="flex items-center justify-center space-x-6">
            <button 
              onClick={() => updateDhikr(-1)}
              className="w-12 h-12 rounded-2xl bg-white/10 hover:bg-white/20 flex items-center justify-center transition-colors"
            >
              <Minus size={24} />
            </button>
            <button 
              onClick={() => updateDhikr(1)}
              className="w-24 h-24 rounded-[2rem] bg-emerald-500 hover:bg-emerald-400 flex items-center justify-center shadow-xl shadow-emerald-500/40 transition-all active:scale-95"
            >
              <Plus size={40} />
            </button>
            <button 
              onClick={() => updateDhikr(10)}
              className="w-12 h-12 rounded-2xl bg-white/10 hover:bg-white/20 flex items-center justify-center transition-colors font-bold text-xs"
            >
              +10
            </button>
          </div>

          <button 
            onClick={resetDhikr}
            className="flex items-center space-x-2 mx-auto text-[10px] uppercase font-bold text-stone-500 hover:text-white transition-colors"
          >
            <RotateCcw size={12} />
            <span>Reset Session</span>
          </button>
        </div>
      </section>
    </div>
  );
};

export default Tracker;

