    const isExpanded = expandedId === dua.id;

    return (
      <div key={dua.id} className={`bg-white rounded-3xl border border-stone-100 overflow-hidden transition-all duration-300 ${isExpanded ? 'ring-2 ring-emerald-500/20' : 'hover:shadow-lg hover:shadow-stone-200/50'}`}>
