                {dua.category}
              </span>
              <h4 className="text-lg font-bold text-stone-800 leading-tight">{dua.title}</h4>
            </div>
            <button 
              onClick={() => toggleBookmark(dua.id)}
              className={`p-2 rounded-full transition-colors ${isBookmarked ? 'text-rose-500 bg-rose-50' : 'text-stone-300 bg-stone-50'}`}
            >
              <Heart size={18} fill={isBookmarked ? "currentColor" : "none"} />
            </button>
          </div>

          <div className="arabic-font text-2xl text-emerald-900 leading-[1.8] text-right my-4" dir="rtl">
            {dua.arabic}
          </div>

          <div className="space-y-4">
            <button 
              onClick={() => setExpandedId(isExpanded ? null : dua.id)}
              className="w-full flex items-center justify-center space-x-1 py-1 text-stone-400 hover:text-emerald-600 transition-colors"
            >
              <ChevronDown size={16} className={`transform transition-transform ${isExpanded ? 'rotate-180' : ''}`} />
              <span className="text-xs font-medium uppercase">{isExpanded ? 'Show Less' : 'Read Translation'}</span>
            </button>

            {isExpanded && (
              <div className="pt-4 border-t border-stone-50 space-y-4 animate-in fade-in slide-in-from-top-2 duration-300">
                <div>
                    <h5 className="text-[10px] uppercase tracking-wider text-stone-400 font-bold mb-1">Transliteration</h5>
                    <p className="text-sm text-stone-600 italic leading-relaxed">{dua.transliteration}</p>
                </div>
                <div>
                    <h5 className="text-[10px] uppercase tracking-wider text-stone-400 font-bold mb-1">Translation</h5>
                    <p className="text-sm text-stone-800 font-medium leading-relaxed">{dua.translation}</p>
                </div>
                <div className="flex justify-between items-center pt-2">
                    <span className="text-[10px] text-stone-400 italic">Ref: {dua.reference}</span>
                    <button className="flex items-center space-x-2 text-emerald-600 text-xs font-bold hover:bg-emerald-50 px-3 py-1.5 rounded-lg transition-colors">
                        <Share2 size={14} />
                        <span>Share</span>
                    </button>
                </div>
              </div>
            )}
          </div>
        </div>
      </div>
    );
  };

  return (
    <div className="space-y-6 animate-in fade-in duration-500">
      {/* Search & Categories */}
      <div className="space-y-4">
        <div className="relative">
          <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-stone-400" size={18} />
          <input 
            type="text" 
            placeholder="Search Duas, translations..." 
            value={searchQuery}
            onChange={(e) => setSearchQuery(e.target.value)}
            className="w-full pl-12 pr-4 py-4 bg-white border border-stone-100 rounded-2xl text-sm focus:outline-none focus:ring-2 focus:ring-emerald-500/10 focus:border-emerald-300 transition-all shadow-sm"
          />
        </div>

        <div className="flex overflow-x-auto pb-2 -mx-1 no-scrollbar space-x-2">
          <button 
            onClick={() => setActiveCategory('All')}
            className={`px-4 py-2 rounded-xl text-sm font-semibold whitespace-nowrap transition-all ${
              activeCategory === 'All' 
                ? 'bg-emerald-800 text-white shadow-lg shadow-emerald-900/10' 
                : 'bg-white text-stone-500 border border-stone-100'
            }`}
          >
            All Duas
          </button>
          {CATEGORIES.map(cat => (
            <button 
              key={cat}
              onClick={() => setActiveCategory(cat)}
              className={`px-4 py-2 rounded-xl text-sm font-semibold whitespace-nowrap transition-all ${
                activeCategory === cat 
                  ? 'bg-emerald-800 text-white shadow-lg shadow-emerald-900/10' 
                  : 'bg-white text-stone-500 border border-stone-100'
              }`}
            >
              {cat}
            </button>
          ))}
        </div>
      </div>

      {/* Dua List */}
      <div className="grid gap-4">
        {filteredDuas.length > 0 ? (
          filteredDuas.map(dua => renderDuaCard(dua))
        ) : (
          <div className="text-center py-20 bg-white rounded-3xl border border-stone-100">
             {/* Fix: Added missing BookOpen icon to imports */}
             <BookOpen size={48} className="mx-auto text-stone-100 mb-4" />
             <p className="text-stone-400 font-medium">No Duas found</p>
          </div>
        )}
      </div>
    </div>
  );
};

export default DuaLibrary;

import React, { useState, useEffect } from 'react';
import { Bell, BellOff, Info, Clock, Volume2, ShieldCheck, Check, X } from 'lucide-react';
import { Reminder } from '../types';

const INITIAL_REMINDERS: Reminder[] = [
  { id: '1', label: 'Fajr Adhan', time: '05:30', enabled: true },
  { id: '2', label: 'Morning Athkar', time: '06:15', enabled: false },
  { id: '3', label: 'Duha Reminder', time: '09:00', enabled: true },
  { id: '4', label: 'Night Dhikr', time: '21:30', enabled: true },
];

const ALERT_TONES = [
  { id: 'calm', name: 'Calm Breeze' },
  { id: 'nature', name: 'Forest Morning' },
  { id: 'adhan_makkah', name: 'Adhan (Makkah)' },
  { id: 'adhan_madinah', name: 'Adhan (Madinah)' },
  { id: 'gentle', name: 'Gentle Bell' },
  { id: 'digital', name: 'Modern Digital' },
];

const Reminders: React.FC = () => {
  const [reminders, setReminders] = useState<Reminder[]>(INITIAL_REMINDERS);
  const [permissionGranted, setPermissionGranted] = useState(false);
  const [selectedTone, setSelectedTone] = useState('calm');
  const [isToneModalOpen, setIsToneModalOpen] = useState(false);

  useEffect(() => {
    const savedTone = localStorage.getItem('alert_tone');
    if (savedTone) setSelectedTone(savedTone);
  }, []);

  const toggleReminder = (id: string) => {
    setReminders(prev => prev.map(r => r.id === id ? { ...r, enabled: !r.enabled } : r));
  };

  const handleEnableNotifications = () => {
    // Simulated permission request
    setPermissionGranted(true);
  };

  const handleSelectTone = (toneId: string) => {
    setSelectedTone(toneId);
    localStorage.setItem('alert_tone', toneId);
    // Simulate a brief preview sound could go here if audio files were available
    setIsToneModalOpen(false);
  };

  const currentToneName = ALERT_TONES.find(t => t.id === selectedTone)?.name || 'Calm';

  return (
    <div className="space-y-8 animate-in fade-in duration-500 relative">
      {/* Permission Card */}
      {!permissionGranted && (
        <section className="bg-amber-50 border border-amber-100 p-6 rounded-3xl space-y-4">
          <div className="flex space-x-4">
            <div className="w-10 h-10 bg-amber-200 rounded-xl flex items-center justify-center text-amber-700 shrink-0">
                <Bell size={20} />
            </div>
            <div>
                <h4 className="font-bold text-amber-900">Enable Notifications</h4>
                <p className="text-sm text-amber-700 leading-relaxed">Stay consistent with your daily goals and never miss a prayer time.</p>
            </div>
          </div>
          <button 
            onClick={handleEnableNotifications}
            className="w-full py-3 bg-amber-600 text-white font-bold rounded-2xl hover:bg-amber-700 transition-colors shadow-lg shadow-amber-900/10"
          >
            Allow Notifications
          </button>
        </section>
      )}

      {/* Stats Summary */}
      <section className="grid grid-cols-2 gap-4">
         <div className="bg-white p-5 rounded-3xl border border-stone-100 shadow-sm">
            <ShieldCheck className="text-emerald-500 mb-2" size={20} />
            <h5 className="text-[10px] font-bold text-stone-400 uppercase tracking-wider">Status</h5>
            <p className="text-lg font-bold text-stone-800">Secured</p>
         </div>
         <button 
           onClick={() => setIsToneModalOpen(true)}
           className="bg-white p-5 rounded-3xl border border-stone-100 shadow-sm text-left hover:border-emerald-200 transition-all group"
         >
            <Volume2 className="text-blue-500 mb-2 group-hover:scale-110 transition-transform" size={20} />
            <h5 className="text-[10px] font-bold text-stone-400 uppercase tracking-wider">Alert Tone</h5>
            <p className="text-lg font-bold text-stone-800 truncate">{currentToneName}</p>
         </button>
      </section>

      {/* Reminders List */}
      <section>
        <div className="flex items-center justify-between mb-4 px-1">
          <h3 className="font-bold text-stone-800">Scheduled Alerts</h3>
          <button className="text-xs font-bold text-emerald-600 hover:text-emerald-700">Add New</button>
        </div>
        <div className="grid gap-3">
          {reminders.map((reminder) => (
            <div 
              key={reminder.id}
              className={`flex items-center justify-between p-5 bg-white rounded-3xl border transition-all ${
                reminder.enabled ? 'border-emerald-100 shadow-sm' : 'border-stone-100 opacity-60'
              }`}
            >
              <div className="flex items-center space-x-4">
                <div className={`w-10 h-10 rounded-2xl flex items-center justify-center transition-colors ${
                  reminder.enabled ? 'bg-emerald-50 text-emerald-600' : 'bg-stone-100 text-stone-400'
                }`}>
                  <Clock size={20} />
                </div>
                <div>
                  <h4 className="font-bold text-stone-800 leading-none mb-1">{reminder.label}</h4>
                  <p className="text-xs text-stone-400 font-medium">{reminder.time}</p>
                </div>
              </div>

              <button 
                onClick={() => toggleReminder(reminder.id)}
                className={`relative inline-flex h-6 w-11 items-center rounded-full transition-colors focus:outline-none ${
                    reminder.enabled ? 'bg-emerald-600' : 'bg-stone-200'
                }`}
              >
                <span
                    className={`inline-block h-4 w-4 transform rounded-full bg-white transition-transform ${
                        reminder.enabled ? 'translate-x-6' : 'translate-x-1'
                    }`}
                />
              </button>
            </div>
          ))}
        </div>
      </section>

      {/* Info Tip */}
      <div className="bg-stone-100/50 p-4 rounded-2xl flex space-x-3 items-start">
        <Info size={16} className="text-stone-400 mt-0.5 shrink-0" />
        <p className="text-xs text-stone-500 leading-relaxed italic">
          Tip: You can change the notification sound to various Adhan types in the global account settings.
        </p>
      </div>

      {/* Tone Selection Modal */}
      {isToneModalOpen && (
        <div className="fixed inset-0 z-50 flex items-end sm:items-center justify-center p-4 bg-stone-900/40 backdrop-blur-sm animate-in fade-in duration-200">
          <div 
            className="bg-white w-full max-w-sm rounded-[2.5rem] p-8 shadow-2xl animate-in slide-in-from-bottom-10 duration-300"
            onClick={(e) => e.stopPropagation()}
          >
            <div className="flex justify-between items-center mb-6">
              <h3 className="text-xl font-bold text-stone-900">Select Alert Tone</h3>
              <button 
                onClick={() => setIsToneModalOpen(false)}
                className="p-2 hover:bg-stone-50 rounded-full transition-colors"
              >
                <X size={20} className="text-stone-400" />
              </button>
            </div>

            <div className="grid gap-2">
              {ALERT_TONES.map((tone) => (
                <button
                  key={tone.id}
                  onClick={() => handleSelectTone(tone.id)}
                  className={`flex items-center justify-between p-4 rounded-2xl transition-all ${
                    selectedTone === tone.id 
                      ? 'bg-emerald-50 text-emerald-800 border-2 border-emerald-500/20' 
                      : 'hover:bg-stone-50 text-stone-600 border-2 border-transparent'
                  }`}
                >
                  <span className="font-semibold">{tone.name}</span>
                  {selectedTone === tone.id && <Check size={18} className="text-emerald-600" />}
                </button>
              ))}
            </div>

            <button 
              onClick={() => setIsToneModalOpen(false)}
              className="w-full mt-6 py-4 bg-stone-900 text-white font-bold rounded-2xl hover:bg-stone-800 transition-colors"
            >
              Confirm
            </button>
          </div>
        </div>
      )}
    </div>
  );
};

export default Reminders;
